uint256 entropy = (slotValue / (10 ** (72 - position))) % 1000000;
uint256 paddedEntropy = entropy * (10 ** (6 - numberOfDigits(entropy)));
return paddedEntropy;

function numberOfDigits(uint256 number) private pure returns (uint256) {
    uint256 digits = 0;
    while (number != 0) {
        number /= 10;
        digits++;
    }
    return digits;
}
